// HasFeature mirrors the Godot DisplayServer.has_feature method.
func (self *DisplayServer) HasFeature(feature DisplayServerFeature) bool {
	var ret bool
	tmp_feature := int64(feature)

	args := [...]gdextension.TypePtr{
		gdextension.TypePtr(unsafe.Pointer(&tmp_feature)),
	}
	gdextension.CallMethodBindPtrCall(displayServerMethodHasFeature(), self.Ptr(), args[:], gdextension.TypePtr(unsafe.Pointer(&ret)))
	return ret
}

